CREATE TABLE provider_executions(id TEXT PRIMARY KEY, user_id TEXT NOT NULL REFERENCES users(id), project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, run_id TEXT REFERENCES runs(id) ON DELETE CASCADE, provider TEXT NOT NULL, model TEXT NOT NULL, execution_mode TEXT NOT NULL, credential_source TEXT NOT NULL, request_id TEXT, input_tokens INTEGER NOT NULL DEFAULT 0, output_tokens INTEGER NOT NULL DEFAULT 0, cost_micros INTEGER NOT NULL DEFAULT 0, status TEXT NOT NULL, error_code TEXT, latency_ms REAL, created_at TEXT NOT NULL, completed_at TEXT);
CREATE INDEX ix_provider_executions_run ON provider_executions(run_id,created_at);
